(window.webpackJsonp=window.webpackJsonp||[]).push([[210],{837:function(n,r){n.exports='\x3c!-- \r\ntitle: 22-PIL入门\r\nsort: \r\n--\x3e \r\n# Pillow入门\r\n\r\n## 使用Image\r\n\r\n```python\r\n>>> from PIL import Image\r\n\r\n>>> im = Image.open("test.jpg")\r\n>>> print(im.format, im.size, im.mode)\r\nJPEG (505, 500) RGB\r\n>>> im.show()\r\n# 展示图片\r\n```\r\n\r\n### 读写图像\r\n\r\n- 转换格式\r\n\r\n  ```python\r\n  import os, sys\r\n  from PIL import Image\r\n  \r\n  for infile in sys.argv[1:]:\r\n      f, e = os.path.splitext(infile)\r\n      outfile = f + ".jpg"\r\n      if infile != outfile:\r\n          try:\r\n              Image.open(infile).save(outfile)\r\n          except IOError:\r\n              print("cannot convert", infile)\r\n  ```    \r\n\r\n### 剪切，粘贴，合并图像\r\n\r\n- 矩形选区\r\n\r\n  ```python\r\n  >>> box = (50,50,100,100)\r\n  >>> copy = im.crop(box)\r\n  >>> copy.show()\r\n  >>> im.paste(copy,(100,100,150,150))\r\n  >>> im.show\r\n  >>> im.save(\'test.png\')\r\n  ```\r\n  \r\n- 颜色通道\r\n\r\n  ```python\r\n  >>> r, g, b = im.split()\t\t# 分离颜色通道\r\n  >>> r.show()\t\t\t\t\t\r\n  >>> im = Image.merge("RGB", (b, g, r))`\t\t# 颜色反转\r\n  ```\r\n\r\n### 几何变换\r\n\r\n```python\r\n>>> im2 = im.resize(128,128)\t\t# 缩小至128*128\r\n>>> im2.rotate(45).show()\r\n# 变换\r\nout = im.transpose(Image.FLIP_LEFT_RIGHT)\t# 左右颠倒\r\nout = im.transpose(Image.FLIP_TOP_BOTTOM)\t# 上下颠倒\r\nout = im.transpose(Image.ROTATE_90)\t\t\t# 旋转角度\r\nout = im.transpose(Image.ROTATE_180)\r\nout = im.transpose(Image.ROTATE_270)\r\n\r\n>>> im.convert(\'L\').show()\t\t\t# 转换为灰度图\r\n```\r\n\r\n### 颜色增强\r\n\r\n'}}]);